"use client";

/**
 * <CategoryArea> — area chart for a single cost category over time, with optional
 * own-history high/low bands (in % mode) and a you-are-here vertical.
 *
 * Tier-2 per CHART-STANDARD §5.1. viewBox = real px width via useChartSize.
 */

import { useMemo } from "react";
import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface CategoryAreaProps {
  /** Time-series values (one per period). */
  data?: number[];
  /** Period labels along the x-axis (must align with data). */
  xLabels?: string[];
  color: string;
  /** Format the y-axis labels and the trailing end-value. */
  fmt: (v: number) => string;
  /** Show own-history high/low bands derived from this series. */
  showBands?: boolean;
  /** Series used to compute the bands (defaults to `data`). */
  bandSeries?: number[];
  /** Stable id used for the gradient — avoid collisions when multiple charts share a page. */
  gradientId: string;
  state?: ChartState;
  label?: string;
}

export const sampleCategoryAreaData: number[] = [17.2, 17.6, 17.4, 18.1, 18.5, 19.6];
export const sampleCategoryAreaLabels: string[] = ["Dec", "Jan", "Feb", "Mar", "Apr", "May"];

export function CategoryArea({
  data = sampleCategoryAreaData,
  xLabels = sampleCategoryAreaLabels,
  color,
  fmt,
  showBands = false,
  bandSeries,
  gradientId,
  state = "ready",
  label = "Category trend",
}: CategoryAreaProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 1100 });
  const W = Math.max(640, width);
  const H = 340;
  const padL = 70;
  const padR = 60;
  const padT = 30;
  const padB = 44;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  if (data.length < 2 && state === "ready") state = "empty";

  let lo = Math.min(...(data.length ? data : [0]));
  let hi = Math.max(...(data.length ? data : [1]));
  const padScale = (hi - lo) * 0.3 || 1;
  lo -= padScale;
  hi += padScale;
  if (lo < 0) lo = 0;
  const span = hi - lo || 1;

  const X = (i: number) =>
    padL + (i / Math.max(1, data.length - 1)) * plotW;
  const Y = (v: number) => padT + (1 - (v - lo) / span) * plotH;
  const pts = data.map((v, i) => ({ x: X(i), y: Y(v) }));
  const linePath = pts.length
    ? "M " + pts.map((p) => p.x.toFixed(1) + " " + p.y.toFixed(1)).join(" L ")
    : "";
  const areaPath = pts.length
    ? linePath +
      ` L ${pts[pts.length - 1].x} ${base} L ${pts[0].x} ${base} Z`
    : "";

  const bands = useMemo(() => {
    if (!showBands) return null;
    const src = bandSeries ?? data;
    if (!src.length) return null;
    return { hi: Math.max(...src), lo: Math.min(...src) };
  }, [showBands, bandSeries, data]);

  const lastVal = data[data.length - 1];

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="catarea-svg" viewBox={`0 0 ${W} ${H}`}>
          <defs>
            <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" stopColor={color} stopOpacity="0.16" />
              <stop offset="1" stopColor={color} stopOpacity="0" />
            </linearGradient>
          </defs>

          {/* Gridlines + y labels */}
          {[0, 1, 2, 3, 4].map((g) => {
            const v = lo + (span * g) / 4;
            const yy = Y(v);
            return (
              <g key={g}>
                <line x1={padL} y1={yy} x2={W - padR} y2={yy} stroke="rgba(0,0,0,0.05)" strokeWidth={0.5} />
                <text x={padL - 12} y={yy + 4} fontSize="12" fill="#8a8d94" textAnchor="end">
                  {fmt(v)}
                </text>
              </g>
            );
          })}

          {/* Own-history bands */}
          {bands && (
            <>
              <line x1={padL} y1={Y(bands.hi)} x2={W - padR} y2={Y(bands.hi)} stroke="rgba(0,0,0,0.18)" strokeWidth={1} strokeDasharray="4 4" />
              <rect x={padL} y={Y(bands.hi) - 11} width={128} height={22} rx={3} fill="#3d4047" />
              <text x={padL + 11} y={Y(bands.hi) + 4} fontSize="10" fill="#fff" fontWeight={600} letterSpacing="0.06em">
                6-MO HIGH {fmt(bands.hi)}
              </text>
              <line x1={padL} y1={Y(bands.lo)} x2={W - padR} y2={Y(bands.lo)} stroke="rgba(0,0,0,0.18)" strokeWidth={1} strokeDasharray="4 4" />
              <rect x={padL} y={Y(bands.lo) - 11} width={124} height={22} rx={3} fill="#8a8d94" />
              <text x={padL + 11} y={Y(bands.lo) + 4} fontSize="10" fill="#fff" fontWeight={600} letterSpacing="0.06em">
                6-MO LOW {fmt(bands.lo)}
              </text>
            </>
          )}

          {/* X labels */}
          {xLabels.slice(-data.length).map((m, i) => (
            <text key={m + i} x={X(i)} y={base + 24} fontSize="12" fill="#8a8d94" textAnchor="middle">
              {m}
            </text>
          ))}

          {/* You-are-here vertical */}
          {pts.length > 0 && (
            <line
              x1={X(data.length - 1)}
              y1={padT}
              x2={X(data.length - 1)}
              y2={base}
              stroke="rgba(0,0,0,0.22)"
              strokeWidth={1}
              strokeDasharray="4 4"
            />
          )}

          {/* Area + line */}
          {areaPath && <path d={areaPath} fill={`url(#${gradientId})`} />}
          {linePath && (
            <path d={linePath} fill="none" stroke={color} strokeWidth={2.6} strokeLinecap="round" strokeLinejoin="round" />
          )}

          {/* Nodes */}
          {pts.map((p, i) => {
            const last = i === pts.length - 1;
            return last ? (
              <rect key={i} x={p.x - 3.6} y={p.y - 3.6} width={7.2} height={7.2} rx={1} fill={color} stroke="#fff" strokeWidth={1.6} />
            ) : (
              <rect key={i} x={p.x - 3.2} y={p.y - 3.2} width={6.4} height={6.4} fill="#fff" stroke={color} strokeWidth={1.5} />
            );
          })}

          {/* End value label */}
          {pts.length > 0 && (
            <text
              x={X(data.length - 1) + 12}
              y={Y(lastVal) + 5}
              fontSize="13"
              fill={color}
              fontWeight={600}
            >
              {fmt(lastVal)}
            </text>
          )}
        </svg>
      </ChartStates>
    </div>
  );
}
