"use client";

import { useState } from "react";
import { notFound, useParams } from "next/navigation";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { CATEGORIES, MONTHS } from "@/features/finance/api/finance-cost-categories-data";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { CategoryArea } from "@/components/charts/CategoryArea";
import "./categoryDetail.css";

type Mode = "pct" | "dol";

export default function CategoryDetailPage() {
  const params = useParams<{ id: string }>();
  const cat = CATEGORIES.find((c) => c.id === params.id);
  if (!cat) return notFound();

  const [mode, setMode] = useState<Mode>("pct");
  const series = mode === "pct" ? cat.pctSeries : cat.dolSeries;
  const isPct = mode === "pct";

  const delta = cat.now - cat.prev;
  const deltaCls = Math.abs(delta) < 0.15 ? "flat" : delta > 0 ? "up" : "dn";
  const deltaTxt =
    deltaCls === "flat"
      ? "steady · 6 mo"
      : (delta > 0 ? "↑" : "↓") + ` from ${cat.prev}% · 6 mo`;

  const monthLabels = MONTHS.slice(-series.length);

  return (
    <div className="finance-cat-detail-page">
      <DeptHeader
        dept="finance"
        title={cat.name}
        meta={
          <>
            <span className="detail-swatch" style={{ background: cat.color }} />
            Cost categories · {cat.tag === "var" ? "Variable" : "Fixed"} · from ledger
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Add category rule →</BridgePrimaryButton>
          </>
        }
      />
      <div className="head-pad" />

      <div className="chart-card">
        <div className="cc-top">
          <div>
            <div className="cc-eyebrow">
              {cat.name} · share of revenue · trailing 6 months
            </div>
            <div className="cc-readout">
              <span className="big">{cat.now}%</span>
              <span className={`delta ${deltaCls}`}>{deltaTxt}</span>
            </div>
            <div className="cc-thresholds">
              Measured from your ledger · judged against its own 6-month history
            </div>
          </div>
          <div className="cc-cluster">
            <div className="cc-live">
              <span className="dot" />
              Live · synced 6 min ago
            </div>
            <div className="cc-toggle">
              <button
                className={mode === "pct" ? "active" : ""}
                onClick={() => setMode("pct")}
                type="button"
              >
                % of revenue
              </button>
              <button
                className={mode === "dol" ? "active" : ""}
                onClick={() => setMode("dol")}
                type="button"
              >
                Dollars
              </button>
            </div>
          </div>
        </div>

        <CategoryArea
          data={series}
          xLabels={monthLabels}
          color={cat.color}
          fmt={(v) => (isPct ? `${v.toFixed(1)}%` : `$${v.toFixed(0)}K`)}
          showBands={isPct}
          bandSeries={cat.pctSeries}
          gradientId={`ccg-${cat.id}`}
        />

        <div className={`cc-arg ${cat.verdict === "ok" ? "ok" : ""}`}>
          <div className="mk" />
          <p dangerouslySetInnerHTML={{ __html: cat.arg }} />
        </div>
      </div>

      {/* Drill grid */}
      <div className="drill-grid">
        <div className="drill">
          <div className="drill-head">
            <span>Breakdown</span>
            <span className="real">
              <span className="d" />
              real transaction data
            </span>
          </div>
          {cat.drill.map((d) => (
            <div key={d.name} className="drill-row">
              <div className="nm">
                {d.name}
                <span className="meta">{d.meta}</span>
              </div>
              <div className="bar">
                <i style={{ width: `${d.bar}%`, background: cat.color }} />
              </div>
              <div className="amt">
                {d.amount}
                <span className={`chg ${d.changeClass}`}>{d.changePct}</span>
              </div>
            </div>
          ))}
        </div>

        <div className="drill">
          <div className="drill-head">Magellan&rsquo;s read</div>
          <div className="drill-cause">
            <div className="ct">The cause</div>
            <div className="cline" dangerouslySetInnerHTML={{ __html: cat.cause }} />
            <BridgePrimaryButton dept="finance" className="cact">
              Add category rule →
            </BridgePrimaryButton>
          </div>
        </div>
      </div>
    </div>
  );
}
